// docsDrawerToggleID is the id of the hidden checkbox controlling the
// page-level drawer sidebar. The navbar menu icon acts as a label for this
// checkbox.
const docsDrawerToggleID = "docs-drawer"

// navItemClass returns the class list for a sidebar nav entry, highlighting
// active items.
func navItemClass(active bool) string {
	if active {
		return "menu-active"
	}
	return ""
}

// isAbsoluteURL reports whether href is an absolute URL (http://, https://,
// //, mailto:, etc.) that should bypass the site-path resolver. The resolver
// prefixes every href with the site base, which corrupts external links like
// "https://github.com/..." into "/sites/<host>/https://github.com/...".
func isAbsoluteURL(href string) bool {
	return strings.HasPrefix(href, "http://") ||
		strings.HasPrefix(href, "https://") ||
		strings.HasPrefix(href, "//") ||
		strings.HasPrefix(href, "mailto:") ||
		strings.HasPrefix(href, "tel:")
}

// resolveNavItem renders an href via the resolver, falling back to "#" for
// empty hrefs. Absolute URLs (http://, https://, //, mailto:, tel:) bypass
// the resolver so external links aren't prefixed with the site path.
func resolveNavItem(r daisyui.URLResolver, href string) templ.SafeURL {
	if href == "" {
		return templ.SafeURL("#")
	}
	if isAbsoluteURL(href) {
		return templ.SafeURL(href)
	}
	if r == nil {
		return templ.SafeURL(href)
	}
	return templ.SafeURL(r.Resolve(href))
}

// toDaisyNavItems converts the layout-agnostic []layouts.NavItem (used by the
// documentation Config) into the []daisyui.NavItem expected by the daisyUI
// Navbar component. Hrefs are pre-resolved here so the navbar's own resolver
// pass is bypassed (nil) — this keeps absolute URLs intact while still
// prefixing site-relative paths with the site base. The two types are
// intentionally separate so this layout package owns the vocabulary for nav
// sections (which carry Active state for sidebar highlighting) without
// forcing the daisyUI component to.
func toDaisyNavItems(r daisyui.URLResolver, items []layouts.NavItem) []daisyui.NavItem {
	out := make([]daisyui.NavItem, len(items))
	for i, item := range items {
		out[i] = daisyui.NavItem{
			Label: item.Label,
			Href:  string(resolveNavItem(r, item.Href)),
		}
	}
	return out
}

